import org.eclipse.rdf4j.query.algebra.ValueConstant;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.helpers.AbstractQueryModelVisitor;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.junit.jupiter.api.Test;

class LmdbSemanticDependencyOptimizerTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI SSN = VF.createIRI("urn:ssn");

	@Test
	void eliminatesDuplicateFunctionalPropertyJoin() {
		QueryRoot root = new QueryRoot(project(functionalFilter("s", "x", "y"), "s", "x"));

		optimize(root, functionalSsnDependencies());

		Projection projection = assertInstanceOf(Projection.class, root.getArg(), () -> root.toString());
		StatementPattern replacement = assertInstanceOf(StatementPattern.class, projection.getArg(),
				() -> root.toString());
		assertEquals("x", replacement.getObjectVar().getName());
		assertEquals(1, countStatementPatterns(root));
		assertFalse(containsFilter(root));
		assertProof(replacement);
	}

	@Test
	void preservesProjectedEliminatedObjectWithExtension() {
		QueryRoot root = new QueryRoot(project(functionalFilter("s", "x", "y"), "s", "x", "y"));

		optimize(root, functionalSsnDependencies());

		Projection projection = assertInstanceOf(Projection.class, root.getArg(), () -> root.toString());
		Extension extension = assertInstanceOf(Extension.class, projection.getArg(), () -> root.toString());
		assertEquals(1, countStatementPatterns(extension));
		assertTrue(extension.getElements().stream().anyMatch(LmdbSemanticDependencyOptimizerTest::copiesXToY));
		assertProof(extension);
	}

	@Test
	void skipsUndeclaredFunctionalPredicate() {
		QueryRoot root = new QueryRoot(project(functionalFilter("s", "x", "y"), "s", "x"));

		optimize(root, LmdbSemanticDependencies.empty());

		assertUnchangedFilterJoin(root);
	}

	@Test
	void skipsDifferentSubjects() {
		Filter filter = new Filter(new Join(statementPattern("s", SSN, "x"), statementPattern("other", SSN, "y")),
				compareVars("x", "y"));
		QueryRoot root = new QueryRoot(project(filter, "s", "x"));

		optimize(root, functionalSsnDependencies());

		assertUnchangedFilterJoin(root);
	}

	@Test
	void skipsContextMismatch() {
		Filter filter = new Filter(
				new Join(statementPattern("s", SSN, "x", VF.createIRI("urn:g1")),
						statementPattern("s", SSN, "y", VF.createIRI("urn:g2"))),
				compareVars("x", "y"));
		QueryRoot root = new QueryRoot(project(filter, "s", "x"));

		optimize(root, functionalSsnDependencies());

		assertUnchangedFilterJoin(root);
	}

	@Test
	void skipsIndependentObjectVarsWithoutEquality() {
		QueryRoot root = new QueryRoot(project(
				new Join(statementPattern("s", SSN, "x"), statementPattern("s", SSN, "y")), "s", "x", "y"));

		optimize(root, functionalSsnDependencies());

		Projection projection = assertInstanceOf(Projection.class, root.getArg(), () -> root.toString());
		assertInstanceOf(Join.class, projection.getArg(), () -> root.toString());
		assertEquals(2, countStatementPatterns(root));
		assertNull(projection.getArg().getStringMetricPlanned("optimizer.rewriteProof"));
	}

	@Test
	void preservesFilterConditionWhenSameObjectVarProvesFunctionalDuplicate() {
		Filter filter = new Filter(
				new Join(statementPattern("s", SSN, "x"), statementPattern("s", SSN, "x")),
				new Compare(new Var("x"), new ValueConstant(VF.createLiteral(5)), Compare.CompareOp.GT));
		QueryRoot root = new QueryRoot(project(filter, "s", "x"));

		optimize(root, functionalSsnDependencies());

		Projection projection = assertInstanceOf(Projection.class, root.getArg(), () -> root.toString());
		Filter retainedFilter = assertInstanceOf(Filter.class, projection.getArg(), () -> root.toString());
		assertEquals(1, countStatementPatterns(retainedFilter));
		assertProof(assertInstanceOf(StatementPattern.class, retainedFilter.getArg(), () -> root.toString()));
	}

	private static LmdbSemanticDependencies functionalSsnDependencies() {
		return LmdbSemanticDependencies.builder().functionalBySubject(SSN).build();
	}

	private static void optimize(TupleExpr tupleExpr, LmdbSemanticDependencies dependencies) {
		new LmdbSemanticDependencyOptimizer(dependencies).optimize(tupleExpr, null, EmptyBindingSet.getInstance());
	}

	private static Filter functionalFilter(String subjectName, String leftObjectName, String rightObjectName) {
		return new Filter(
				new Join(statementPattern(subjectName, SSN, leftObjectName),
						statementPattern(subjectName, SSN, rightObjectName)),
				compareVars(leftObjectName, rightObjectName));
	}

	private static StatementPattern statementPattern(String subjectName, IRI predicate, String objectName) {
		return new StatementPattern(new Var(subjectName), new Var("predicate", predicate), new Var(objectName));
	}

	private static StatementPattern statementPattern(String subjectName, IRI predicate, String objectName,
			IRI context) {
		return new StatementPattern(new Var(subjectName), new Var("predicate", predicate), new Var(objectName),
				new Var("context", context));
	}

	private static Compare compareVars(String leftVarName, String rightVarName) {
		return new Compare(new Var(leftVarName), new Var(rightVarName), Compare.CompareOp.EQ);
	}

	private static Projection project(TupleExpr arg, String... names) {
		ProjectionElemList projectionElemList = new ProjectionElemList();
		for (String name : names) {
			projectionElemList.addElement(new ProjectionElem(name));
		}
		return new Projection(arg, projectionElemList);
	}

	private static boolean copiesXToY(ExtensionElem elem) {
		return "y".equals(elem.getName()) && elem.getExpr()instanceof Var var && "x".equals(var.getName());
	}

	private static void assertUnchangedFilterJoin(QueryRoot root) {
		Projection projection = assertInstanceOf(Projection.class, root.getArg(), () -> root.toString());
		Filter filter = assertInstanceOf(Filter.class, projection.getArg(), () -> root.toString());
		assertInstanceOf(Join.class, filter.getArg(), () -> root.toString());
		assertEquals(2, countStatementPatterns(root));
		assertNull(filter.getStringMetricPlanned("optimizer.rewriteProof"));
	}

	private static void assertProof(TupleExpr tupleExpr) {
		String proof = tupleExpr.getStringMetricPlanned("optimizer.rewriteProof");
		assertNotNull(proof);
		assertTrue(proof.contains("DEPENDENCY_FUNCTIONAL_JOIN_ELIMINATION"), proof);
		assertTrue(proof.contains("LOGICAL_BAG_EQUIVALENT"), proof);
	}

	private static int countStatementPatterns(TupleExpr tupleExpr) {
		int[] count = { 0 };
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(StatementPattern node) {
				count[0]++;
			}
		});
		return count[0];
	}

	private static boolean containsFilter(TupleExpr tupleExpr) {
		boolean[] found = { false };
		tupleExpr.visit(new AbstractQueryModelVisitor<RuntimeException>() {
			@Override
			public void meet(Filter node) {
				found[0] = true;
				super.meet(node);
			}
		});
		return found[0];
	}
}
